 11→// BinPath returns the path to the entire binary.
 12→// It checks E2E_ENTIRE_BIN first, then falls back to looking in PATH.
 13→func BinPath() string {
 14→	if p := os.Getenv("E2E_ENTIRE_BIN"); p != "" {
 15→		return p
 16→	}
 17→	if p, err := exec.LookPath("entire"); err == nil {
 18→		return p
 19→	}
 20→	return "entire"
 21→}
