 46→// RewindList runs `entire rewind --list` and parses the JSON output.
 47→func RewindList(t *testing.T, dir string) []RewindPoint {
 48→	t.Helper()
 49→	out := run(t, dir, "rewind", "--list")
 50→
 51→	var points []RewindPoint
 52→	if err := json.Unmarshal([]byte(out), &points); err != nil {
 53→		t.Fatalf("parse rewind list: %v\nraw output: %s", err, out)
 54→	}
 55→	return points
 56→}
